/**
 * Summarize observed Cesar tool reliability for one engine/backend from decision records.
 */
// @kern-source: reliability:108
export function summarizeCesarToolReliability(records: any[], engineId?: string, backend?: string): CesarToolReliability {
  const targetEngine = String(engineId ?? '').trim();
  const targetBackend = String(backend ?? '').trim();
  const filtered = records.filter((record: any) => {
    const recEngine = String(record.engineId ?? record.cesarEngineId ?? 'unknown');
    const recBackend = String(record.backend ?? record.cesarBackend ?? 'unknown');
    if (targetEngine && recEngine !== targetEngine) return false;
    if (targetBackend && targetBackend !== 'all' && targetBackend !== 'auto' && recBackend !== targetBackend) return false;
    return true;
  });

  if (filtered.length === 0) {
    return emptyCesarToolReliability(targetEngine || 'all', (targetBackend && targetBackend !== 'auto') ? targetBackend : 'all');
  }

  let toolTurns = 0;
  let toolHeavyTurns = 0;
  let toolHeavyToolTurns = 0;
  let toolCount = 0;
  let nativeToolCalls = 0;
  let mcpToolCalls = 0;
  let xmlToolCalls = 0;
  let narratedToolStalls = 0;
  let autoToolExecutions = 0;
  let confidenceToolTurns = 0;
  const toolNames: Record<string, number> = {};

  for (const record of filtered) {
    const count = Number(record.toolCount ?? 0);
    const heavy = isToolHeavyCesarRecord(record);
    toolCount += Number.isFinite(count) ? count : 0;
    nativeToolCalls += Number(record.nativeToolCalls ?? 0) || 0;
    mcpToolCalls += Number(record.mcpToolCalls ?? 0) || 0;
    xmlToolCalls += Number(record.xmlToolCalls ?? 0) || 0;
    narratedToolStalls += Number(record.narratedToolStalls ?? 0) || 0;
    autoToolExecutions += Number(record.autoToolExecutions ?? 0) || 0;
    if (count > 0) toolTurns++;
    if (heavy) {
      toolHeavyTurns++;
      if (count > 0) toolHeavyToolTurns++;
    }
    if (record.confidenceToolUsed === true) confidenceToolTurns++;
    if (Array.isArray(record.toolsUsed)) {
      for (const rawName of record.toolsUsed) {
        const name = String(rawName || '').trim();
        if (!name) continue;
        toolNames[name] = (toolNames[name] ?? 0) + 1;
      }
    }
  }

  const turns = filtered.length;
  const toolTurnRate = turns > 0 ? toolTurns / turns : 0;
  const toolHeavyToolRate = toolHeavyTurns > 0 ? toolHeavyToolTurns / toolHeavyTurns : 0;
  const avgTools = turns > 0 ? toolCount / turns : 0;
  const stallRate = turns > 0 ? narratedToolStalls / turns : 0;
  const confidenceToolRate = turns > 0 ? confidenceToolTurns / turns : 0;
  const sampleEngine = targetEngine || String(filtered[filtered.length - 1]?.engineId ?? filtered[filtered.length - 1]?.cesarEngineId ?? 'all');
  const sampleBackend = (targetBackend && targetBackend !== 'auto')
    ? targetBackend
    : String(filtered[filtered.length - 1]?.backend ?? filtered[filtered.length - 1]?.cesarBackend ?? 'all');
  const topTools = Object.entries(toolNames)
    .sort((a, b) => b[1] - a[1])
    .slice(0, 4)
    .map(([name, count]) => `${name}:${count}`)
    .join(', ') || '-';

  let label: CesarReliabilityLabel = 'unknown';
  let reason = 'Need at least 3 logged Cesar turns before judging tool reliability.';
  if (turns >= 3) {
    if (
      (toolHeavyTurns >= 3 && toolHeavyToolRate <= 0.1 && narratedToolStalls > 0)
      || (toolHeavyTurns >= 3 && toolHeavyToolRate <= 0.2 && (narratedToolStalls >= 2 || confidenceToolRate < 0.5))
      || (stallRate >= 0.35 && narratedToolStalls >= 2)
    ) {
      label = 'advisory-only';
      reason = `Tool-heavy turns rarely produced tools (${toolHeavyToolTurns}/${toolHeavyTurns}); stalls ${narratedToolStalls}.`;
    } else if (
      (toolHeavyTurns >= 3 && toolHeavyToolRate < 0.45)
      || stallRate >= 0.2
      || (turns >= 5 && confidenceToolRate < 0.5 && toolTurnRate < 0.25)
    ) {
      label = 'watch';
      reason = `Tool use is inconsistent (${toolTurns}/${turns} turns; tool-heavy ${toolHeavyToolTurns}/${toolHeavyTurns}; stalls ${narratedToolStalls}).`;
    } else if (toolTurns > 0 || confidenceToolTurns > 0 || nativeToolCalls + mcpToolCalls + xmlToolCalls > 0) {
      label = 'tool-capable';
      reason = `Observed tool use on ${toolTurns}/${turns} turns with ${narratedToolStalls} narrated stalls.`;
    } else {
      label = 'unknown';
      reason = 'Enough turns exist, but none were tool-heavy enough to judge direct tool use.';
    }
  }

  return {
    engineId: sampleEngine,
    backend: sampleBackend,
    turns,
    toolTurns,
    toolTurnRate,
    toolHeavyTurns,
    toolHeavyToolTurns,
    toolHeavyToolRate,
    avgTools,
    nativeToolCalls,
    mcpToolCalls,
    xmlToolCalls,
    narratedToolStalls,
    stallRate,
    autoToolExecutions,
    confidenceToolTurns,
    confidenceToolRate,
    topTools,
    label,
    reason,
  };
}

/**
 * Read and summarize recent Cesar tool reliability, falling back from exact backend to any backend for the same engine.
 */
// @kern-source: reliability:227
export function readCesarToolReliability(engineId?: string, backend?: string, limit?: number): CesarToolReliability {
  const records = readCesarDecisionRecords(limit ?? 200);
  let summary = summarizeCesarToolReliability(records, engineId, backend);
  if (summary.turns === 0 && backend && backend !== 'all' && backend !== 'auto') {
    summary = summarizeCesarToolReliability(records, engineId, undefined);
  }
  return summary;
}

/**
 * Summarize recent Cesar tool reliability for every observed engine/backend pair.
 */
// @kern-source: reliability:238
export function summarizeAllCesarToolReliability(limit?: number): CesarToolReliability[] {
  const records = readCesarDecisionRecords(limit ?? 200);
  const pairs = new Map<string, { engineId: string; backend: string }>();
  for (const record of records) {
    const engineId = String(record.engineId ?? record.cesarEngineId ?? 'unknown');
    const backend = String(record.backend ?? record.cesarBackend ?? 'unknown');
    pairs.set(`${engineId}:::${backend}`, { engineId, backend });
  }
  return Array.from(pairs.values())
    .map((pair) => summarizeCesarToolReliability(records, pair.engineId, pair.backend))
    .sort((a, b) => b.turns - a.turns || a.engineId.localeCompare(b.engineId));
}

// @kern-source: reliability:253
export function formatCesarReliabilityLine(summary: CesarToolReliability): string {
  if (!summary || summary.turns <= 0) {
    const engine = summary?.engineId ?? 'all';
    const backend = summary?.backend ?? 'all';
    return `${engine}/${backend}: unknown - no logged turns yet`;
  }
  const toolPct = Math.round(summary.toolTurnRate * 100);
  const heavy = summary.toolHeavyTurns > 0
    ? `, tool-heavy ${summary.toolHeavyToolTurns}/${summary.toolHeavyTurns}`
    : '';
  return `${summary.engineId}/${summary.backend}: ${summary.label} (${summary.toolTurns}/${summary.turns} tool turns, ${toolPct}%${heavy}, stalls ${summary.narratedToolStalls}) - ${summary.reason}`;
}

/**
 * Return true when Cesar should bias away from self-tooling and toward plan/orchestration for this turn.
 */
// @kern-source: reliability:267
export function shouldDowngradeCesarToolWork(summary: CesarToolReliability, intakeKind?: string, recommendedFlow?: string): boolean {
  const intake = String(intakeKind ?? '').toLowerCase();
  const flow = String(recommendedFlow ?? '').toLowerCase();
  const toolHeavy = [
    'quick-fix', 'bug', 'feature', 'big-feature', 'review',
  ].includes(intake) || [
    'quick-fix', 'bug-fix', 'plan-first', 'forge-slice', 'forge-full', 'review',
  ].includes(flow);
  if (!toolHeavy) return false;
  if (summary.label === 'advisory-only') return true;
  return summary.label === 'watch' && summary.toolHeavyTurns >= 3 && summary.toolHeavyToolRate < 0.35;
}

/**
 * Build a compact visible summary of the actual tools Cesar used this turn.
 */
// @kern-source: reliability:282
export function buildWhatHappenedSummary(telemetry: Record<string,unknown>): string {
  const toolCount = Number(telemetry?.toolCount ?? 0) || 0;
  const eventCount = Number(telemetry?.toolEventCount ?? 0) || 0;
  const native = Number(telemetry?.nativeToolCalls ?? 0) || 0;
  const mcp = Number(telemetry?.mcpToolCalls ?? 0) || 0;
  const xml = Number(telemetry?.xmlToolCalls ?? 0) || 0;
  const stalls = Number(telemetry?.narratedToolStalls ?? 0) || 0;
  const auto = Number(telemetry?.autoToolExecutions ?? 0) || 0;
  const confidence = telemetry?.confidenceToolUsed === true;
  if (toolCount <= 0 && eventCount <= 0 && stalls <= 0 && auto <= 0 && !confidence) return '';

  const counts: Record<string, number> = {};
  if (Array.isArray(telemetry?.toolsUsed)) {
    for (const raw of telemetry.toolsUsed as unknown[]) {
      const name = String(raw || '').trim();
      if (!name) continue;
      counts[name] = (counts[name] ?? 0) + 1;
    }
  }
  const top = Object.entries(counts)
    .sort((a, b) => b[1] - a[1])
    .slice(0, 4)
    .map(([name, count]) => count > 1 ? `${name} x${count}` : name)
    .join(', ');

  const parts: string[] = [];
  if (toolCount > 0) parts.push(`${toolCount} tool${toolCount === 1 ? '' : 's'}${top ? ` (${top})` : ''}`);
  else if (eventCount > 0) parts.push(`${eventCount} tool event${eventCount === 1 ? '' : 's'}`);
  if (native + mcp + xml > 0) parts.push(`native/mcp/xml ${native}/${mcp}/${xml}`);
  if (confidence) parts.push('confidence via tool');
  if (stalls > 0) parts.push(`${stalls} narrated stall${stalls === 1 ? '' : 's'}`);
  if (auto > 0) parts.push(`${auto} auto execution${auto === 1 ? '' : 's'}`);
  return parts.length > 0 ? `What happened: ${parts.join(' | ')}` : '';
}
